const projects = items.map(item => item.json);
const date = new Date().toLocaleDateString('en-GB', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

const rows = projects.map(p => {
  const title = p.title ?? p.name ?? 'Unnamed Project';
  const start = p.startDate ? new Date(p.startDate).toLocaleDateString('en-GB') : '—';
  const end = p.endDate ? new Date(p.endDate).toLocaleDateString('en-GB') : '—';
  return `<tr><td style="padding:8px;border:1px solid #ddd;">${title}</td><td style="padding:8px;border:1px solid #ddd;text-align:center;">${start}</td><td style="padding:8px;border:1px solid #ddd;text-align:center;">${end}</td></tr>`;
}).join('');

const html = `
<html><body style="font-family:Arial,sans-serif;color:#333;">
<h2 style="color:#1a1a2e;">📊 Weekly smenso Project Report</h2>
<p style="color:#666;">${date}</p>
<p>You have <strong>${projects.length} active project(s)</strong> in your smenso workspace.</p>
<table style="border-collapse:collapse;width:100%;margin-top:16px;">
  <thead>
    <tr style="background:#f0f0f0;">
      <th style="padding:8px;border:1px solid #ddd;text-align:left;">Project</th>
      <th style="padding:8px;border:1px solid #ddd;">Start Date</th>
      <th style="padding:8px;border:1px solid #ddd;">End Date</th>
    </tr>
  </thead>
  <tbody>${rows}</tbody>
</table>
<p style="margin-top:24px;color:#999;font-size:12px;">This report was automatically generated by n8n + smenso.</p>
</body></html>
`;

return [{ json: { html, projectCount: projects.length, date } }];
